const path = "~/contacts.yaml";
const text = await space.api.fileRead(path, "utf8");
const data = space.utils.yaml.parse(text);

function updateValue(obj) {
  if (Array.isArray(obj)) {
    return obj.map(updateValue);
  }
  if (obj && typeof obj === "object") {
    const out = {};
    for (const [k, v] of Object.entries(obj)) {
      if (k === "mr_kowalski" && typeof v === "string") {
        out[k] = "John Ronald Kowalski";
      } else {
        out[k] = updateValue(v);
      }
    }
    return out;
  }
  return obj;
}

const updated = updateValue(data);
await space.api.fileWrite(path, space.utils.yaml.stringify(updated), "utf8");
return "updated";

